import { createClient } from "@/lib/supabase/server";
import {
  Trophy,
  Users,
  Gamepad2,
  BarChart3,
  TrendingUp,
  ShieldAlert,
} from "lucide-react";
import { Link } from "@/lib/i18n/routing";
import { getTranslations } from "next-intl/server";

export async function generateMetadata({
  params,
}: {
  params: Promise<{ locale: string }>;
}) {
  const { locale } = await params;
  const t = await getTranslations({ locale, namespace: "Metadata" });
  return { title: t("admin_dashboard") };
}

export default async function AdminDashboardPage() {
  const supabase = await createClient();

  // Fetch Global Stats
  const { count: userCount } = await supabase
    .from("profiles")
    .select("*", { count: "exact", head: true });
  const { count: tournamentCount } = await supabase
    .from("tournaments")
    .select("*", { count: "exact", head: true });
  const { count: gameCount } = await supabase
    .from("games")
    .select("*", { count: "exact", head: true });
  const { count: registrationCount } = await supabase
    .from("registrations")
    .select("*", { count: "exact", head: true });

  // Fetch Real Recent Activity
  const { data: recentRegistrations } = await supabase
    .from("registrations")
    .select("*, profiles(nickname), tournaments(name)")
    .order("created_at", { ascending: false })
    .limit(5);

  const stats = [
    {
      label: "Total Users",
      value: userCount || 0,
      icon: Users,
      color: "text-brand-primary",
      trend: "Global users",
    },
    {
      label: "Total Tournaments",
      value: tournamentCount || 0,
      icon: Trophy,
      color: "text-warning",
      trend: "Created arenas",
    },
    {
      label: "Game Library",
      value: gameCount || 0,
      icon: Gamepad2,
      color: "text-success",
      trend: "Supported titles",
    },
    {
      label: "Total Registrations",
      value: registrationCount || 0,
      icon: BarChart3,
      color: "text-info",
      trend: "Player entries",
    },
  ];

  return (
    <div className="space-y-12 animate-in fade-in slide-in-from-bottom-4 duration-700">
      {/* HEADER */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-6">
        <div>
          <div className="flex items-center gap-3 mb-2">
            <span className="h-2 w-2 rounded-full bg-brand-primary animate-pulse"></span>
            <span className="text-[10px] font-black text-brand-primary uppercase tracking-[0.4em]">
              Live Telemetry
            </span>
          </div>
          <h1 className="font-display text-5xl font-black uppercase tracking-tighter text-white">
            System Overview
          </h1>
          <p className="text-text-secondary mt-2 font-medium">
            Real-time platform metrics and global administration.
          </p>
        </div>
      </div>

      {/* STATS GRID */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8">
        {stats.map((stat, i) => (
          <div
            key={i}
            className="bg-[#0c0c0e] border border-white/5 rounded-[2.5rem] p-10 hover:border-brand-primary/30 transition-all group relative overflow-hidden shadow-2xl"
          >
            <div className="absolute top-0 right-0 p-8 opacity-5 group-hover:opacity-20 transition-all duration-700">
              <stat.icon className="h-24 w-24" />
            </div>
            <div className="flex items-center justify-between mb-6 relative z-10">
              <span className="text-[11px] text-text-tertiary font-black uppercase tracking-[0.2em]">
                {stat.label}
              </span>
              <stat.icon className={`h-5 w-5 ${stat.color}`} />
            </div>
            <div className="font-display text-5xl font-black text-white relative z-10 mb-2">
              {stat.value}
            </div>
            <div className="flex items-center gap-2 text-[10px] font-bold text-text-tertiary uppercase tracking-widest relative z-10">
              {stat.trend}
            </div>
          </div>
        ))}
      </div>

      {/* RECENT ACTIVITY */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-10">
        <div className="lg:col-span-2 space-y-8">
          <div className="flex items-center justify-between">
            <h2 className="font-display text-2xl font-black uppercase tracking-tight text-white">
              Recent Registrations
            </h2>
            <Link
              href="/admin/reports"
              className="text-[10px] text-brand-primary font-black uppercase tracking-[0.2em] hover:text-white transition-colors"
            >
              View All Logs
            </Link>
          </div>
          <div className="bg-[#0c0c0e] border border-white/5 rounded-[3rem] overflow-hidden shadow-2xl">
            <div className="p-4 bg-white/2 border-b border-white/5 grid grid-cols-4 text-[10px] font-black uppercase tracking-widest text-text-tertiary px-10">
              <span>Player</span>
              <span>Tournament</span>
              <span>Applied At</span>
              <span className="text-right">Status</span>
            </div>
            <div className="divide-y divide-white/5">
              {recentRegistrations?.length === 0 ? (
                <div className="p-20 text-center text-text-tertiary uppercase font-black tracking-widest text-xs">
                  No activity yet
                </div>
              ) : (
                recentRegistrations?.map((reg) => (
                  <div
                    key={reg.id}
                    className="px-10 py-6 grid grid-cols-4 items-center hover:bg-white/2 transition-all"
                  >
                    <div className="flex items-center gap-3">
                      <div className="h-8 w-8 rounded-full bg-brand-primary/20 flex items-center justify-center text-brand-primary text-[10px] font-black uppercase">
                        {reg.profiles?.nickname?.charAt(0) || "P"}
                      </div>
                      <span className="text-sm font-black text-white">
                        {reg.profiles?.nickname}
                      </span>
                    </div>
                    <span className="text-xs font-bold text-text-secondary truncate">
                      {reg.tournaments?.name}
                    </span>
                    <span className="text-xs text-text-tertiary font-medium">
                      {new Date(reg.created_at).toLocaleDateString()}
                    </span>
                    <div className="text-right">
                      <span
                        className={`text-[9px] px-3 py-1 rounded-full font-black uppercase tracking-wider ${
                          reg.status === "approved"
                            ? "bg-success/10 text-success border border-success/20"
                            : reg.status === "pending"
                              ? "bg-warning/10 text-warning border border-warning/20"
                              : "bg-white/5 text-text-tertiary"
                        }`}
                      >
                        {reg.status}
                      </span>
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>
        </div>

        <div className="space-y-8">
          <h2 className="font-display text-2xl font-black uppercase tracking-tight text-white">
            System Tools
          </h2>
          <div className="space-y-4">
            {[
              {
                label: "Register Game",
                icon: Gamepad2,
                href: "/admin/games/new",
              },
              {
                label: "Platform Config",
                icon: BarChart3,
                href: "/admin/settings",
              },
              {
                label: "Global Audit",
                icon: ShieldAlert,
                href: "/admin/reports",
              },
            ].map((action, i) => (
              <Link key={i} href={action.href} className="block group">
                <div className="p-8 bg-white/2 border border-white/5 rounded-[2rem] hover:bg-brand-primary hover:border-brand-primary transition-all duration-500 shadow-xl">
                  <div className="flex items-center justify-between">
                    <div className="flex items-center gap-5">
                      <action.icon className="h-6 w-6 text-brand-primary group-hover:text-white transition-colors" />
                      <span className="font-black uppercase tracking-widest text-white">
                        {action.label}
                      </span>
                    </div>
                    <span className="text-2xl text-brand-primary group-hover:text-white transition-colors">
                      →
                    </span>
                  </div>
                </div>
              </Link>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}

import { createClient } from "@/lib/supabase/server";
import {
  AlertTriangle,
  CheckCircle2,
  Clock,
  Trash2,
  User,
  Trophy,
  ExternalLink,
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { Link } from "@/lib/i18n/routing";
import { updateReportStatus, deleteReport } from "./actions";

export default async function AdminIssuesPage() {
  const supabase = await createClient();
  const { data: reports } = await supabase
    .from("reports")
    .select(
      `
      *,
      tournaments(name),
      reporter:profiles!reporter_id(nickname)
    `,
    )
    .order("created_at", { ascending: false });

  return (
    <div className="space-y-12 animate-in fade-in duration-700">
      {/* HEADER */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-6">
        <div>
          <h1 className="font-display text-5xl font-black uppercase tracking-tighter text-white">
            Conflict Issues
          </h1>
          <p className="text-text-secondary mt-2 font-medium">
            Manage and resolve reports submitted by the community.
          </p>
        </div>
      </div>

      {/* ISSUES LIST */}
      <div className="space-y-6">
        {reports?.length === 0 ? (
          <div className="bg-[#0c0c0e] border border-white/5 rounded-[3rem] p-20 text-center shadow-2xl">
            <CheckCircle2 className="mx-auto h-20 w-20 text-success/20 mb-8" />
            <h3 className="font-display text-2xl font-black uppercase tracking-tight text-white mb-3">
              All Clear
            </h3>
            <p className="text-text-secondary font-medium">
              No pending reports or conflicts at this time.
            </p>
          </div>
        ) : (
          reports?.map((report) => (
            <div
              key={report.id}
              className="bg-[#0c0c0e] border border-white/5 rounded-[2.5rem] p-8 hover:border-brand-primary/30 transition-all shadow-2xl group relative overflow-hidden"
            >
              <div className="absolute top-0 right-0 w-32 h-32 bg-brand-primary/5 blur-3xl rounded-full -mr-16 -mt-16 group-hover:bg-brand-primary/10 transition-all duration-700"></div>

              <div className="flex flex-col md:flex-row justify-between gap-8 relative z-10">
                <div className="space-y-6 flex-1">
                  <div className="flex flex-wrap items-center gap-4">
                    <div
                      className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest border ${
                        report.status === "pending"
                          ? "bg-warning/10 text-warning border-warning/20"
                          : "bg-success/10 text-success border-success/20"
                      }`}
                    >
                      {report.status}
                    </div>
                    <span className="text-xs font-bold text-text-tertiary tabular-nums">
                      {new Date(report.created_at).toLocaleString()}
                    </span>
                  </div>

                  <div>
                    <h3 className="text-xl font-black text-white uppercase tracking-tight group-hover:text-brand-primary transition-colors">
                      {report.reason}
                    </h3>
                    <div className="flex flex-wrap gap-6 mt-4">
                      <div className="flex items-center gap-2 text-[10px] text-text-tertiary font-black uppercase tracking-widest">
                        <Trophy className="h-3.5 w-3.5 text-brand-primary" />
                        {report.tournaments?.name || "Unknown Tournament"}
                      </div>
                      <div className="flex items-center gap-2 text-[10px] text-text-tertiary font-black uppercase tracking-widest">
                        <User className="h-3.5 w-3.5 text-brand-primary" />
                        Reported by: {report.reporter?.nickname || "System"}
                      </div>
                    </div>
                  </div>

                  {report.match_id && (
                    <Link
                      href={`/admin/matches/${report.match_id}`}
                      className="inline-flex items-center gap-2 text-[10px] font-black uppercase tracking-widest text-brand-primary hover:text-white transition-colors"
                    >
                      <ExternalLink className="h-3.5 w-3.5" /> View Related
                      Match
                    </Link>
                  )}
                </div>

                <div className="flex flex-col gap-3 justify-center md:min-w-[200px]">
                  {report.status === "pending" && (
                    <form
                      action={async () => {
                        "use server";
                        await updateReportStatus(report.id, "resolved");
                      }}
                    >
                      <Button className="w-full bg-success text-white hover:bg-white hover:text-black font-black uppercase tracking-widest text-[11px] h-12 rounded-xl transition-all">
                        <CheckCircle2 className="mr-2 h-4 w-4" /> Resolve Issue
                      </Button>
                    </form>
                  )}
                  <form
                    action={async () => {
                      "use server";
                      await deleteReport(report.id);
                    }}
                  >
                    <Button
                      variant="ghost"
                      className="w-full text-text-tertiary hover:text-error hover:bg-error/5 font-black uppercase tracking-widest text-[11px] h-12 rounded-xl transition-all"
                    >
                      <Trash2 className="mr-2 h-4 w-4" /> Dismiss Report
                    </Button>
                  </form>
                </div>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
}

"use client";

import { useState, useTransition } from "react";
import { Plus, Edit2, Trash2, Monitor, Loader2, Save, X } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { PremiumModal } from "@/components/ui/PremiumModal";
import { useRouter } from "next/navigation";
import { createPlatform, updatePlatform, deletePlatform } from "./actions";
import { useTranslations } from "next-intl";

interface Platform {
  id: string;
  name: string;
  icon_url: string | null;
}

export function PlatformManagement({
  initialPlatforms,
}: {
  initialPlatforms: Platform[];
}) {
  const t = useTranslations("Admin");
  const common = useTranslations("Common");
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingPlatform, setEditingPlatform] = useState<Platform | null>(null);
  const [isPending, startTransition] = useTransition();
  const [error, setError] = useState<string | null>(null);
  const router = useRouter();

  const handleOpenModal = (platform: Platform | null = null) => {
    setEditingPlatform(platform);
    setError(null);
    setIsModalOpen(true);
  };

  const handleCloseModal = () => {
    setEditingPlatform(null);
    setIsModalOpen(false);
  };

  const handleSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    setError(null);
    const formData = new FormData(e.currentTarget);

    startTransition(async () => {
      let result;
      if (editingPlatform) {
        formData.append("id", editingPlatform.id);
        result = await updatePlatform(formData);
      } else {
        result = await createPlatform(formData);
      }

      if (result.success) {
        handleCloseModal();
        router.refresh();
      } else {
        setError(result.error || "Something went wrong");
      }
    });
  };

  const handleDelete = async (id: string) => {
    if (!confirm(t("confirm_delete"))) return;

    startTransition(async () => {
      const result = await deletePlatform(id);
      if (result.success) {
        router.refresh();
      } else {
        alert(result.error);
      }
    });
  };

  return (
    <div className="space-y-12 animate-in fade-in duration-700">
      {/* HEADER */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-6">
        <div>
          <h1 className="font-display text-5xl font-black uppercase tracking-tighter text-white">
            {t("platforms")}
          </h1>
          <p className="text-text-secondary mt-2 font-medium">
            {t("platforms_subtitle")}
          </p>
        </div>
        <Button
          onClick={() => handleOpenModal()}
          className="bg-brand-primary text-white hover:bg-white hover:text-black hover:shadow-[0_0_30px_rgba(244,0,9,0.5)] transition-all font-black uppercase tracking-widest px-10 py-7 rounded-2xl text-base shadow-2xl"
        >
          <Plus className="mr-3 h-5 w-5" /> {t("add_platform")}
        </Button>
      </div>

      {/* PLATFORMS GRID */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-8">
        {initialPlatforms.map((platform) => (
          <div
            key={platform.id}
            className="bg-[#0c0c0e] border border-white/5 rounded-[2.5rem] p-8 group hover:border-brand-primary/50 transition-all duration-500 shadow-2xl flex flex-col items-center text-center relative overflow-hidden"
          >
            <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-brand-primary/20 to-transparent opacity-0 group-hover:opacity-100 transition-opacity"></div>

            <div className="h-20 w-20 rounded-2xl bg-white/5 flex items-center justify-center mb-6 group-hover:bg-brand-primary/10 group-hover:scale-110 transition-all duration-500 border border-white/5">
              {platform.icon_url ? (
                <img
                  src={platform.icon_url}
                  alt={platform.name}
                  className="h-10 w-10 object-contain"
                />
              ) : (
                <Monitor className="h-10 w-10 text-text-tertiary group-hover:text-brand-primary transition-colors" />
              )}
            </div>

            <h3 className="font-display text-2xl font-black text-white uppercase tracking-tight mb-2 group-hover:text-brand-primary transition-colors">
              {platform.name}
            </h3>

            <div className="mt-8 grid grid-cols-2 gap-4 w-full opacity-0 group-hover:opacity-100 transition-all translate-y-4 group-hover:translate-y-0">
              <Button
                variant="outline"
                onClick={() => handleOpenModal(platform)}
                className="w-full border-white/5 text-white hover:bg-white/5 font-black uppercase tracking-widest text-[10px] rounded-xl h-11 transition-all"
              >
                <Edit2 className="mr-2 h-3 w-3 text-brand-primary" />{" "}
                {common("edit")}
              </Button>
              <Button
                variant="ghost"
                onClick={() => handleDelete(platform.id)}
                className="w-full text-text-tertiary hover:text-error hover:bg-error/5 font-black uppercase tracking-widest text-[10px] rounded-xl h-11 transition-all"
              >
                <Trash2 className="mr-2 h-3 w-3" /> {common("delete")}
              </Button>
            </div>
          </div>
        ))}

        {/* Add New Card */}
        <button
          onClick={() => handleOpenModal()}
          className="group h-full min-h-[300px] border-2 border-dashed border-white/5 rounded-[2.5rem] flex flex-col items-center justify-center p-10 hover:border-brand-primary/50 hover:bg-brand-primary/5 transition-all duration-500"
        >
          <div className="h-16 w-16 rounded-full bg-white/5 flex items-center justify-center mb-6 group-hover:bg-brand-primary group-hover:text-white transition-all duration-500 shadow-2xl">
            <Plus className="h-8 w-8 text-text-tertiary group-hover:text-white transition-colors" />
          </div>
          <div className="text-center">
            <div className="font-display text-xl font-black text-white uppercase tracking-tight mb-2">
              {t("add_platform")}
            </div>
          </div>
        </button>
      </div>

      <PremiumModal
        isOpen={isModalOpen}
        onClose={handleCloseModal}
        title={editingPlatform ? t("edit_platform") : t("add_platform")}
        description="Global Device Configuration"
        variant="default"
      >
        <form onSubmit={handleSubmit} className="space-y-8 py-4">
          {error && (
            <div className="p-4 bg-error/10 border border-error/20 rounded-xl text-error text-[10px] font-black uppercase tracking-widest animate-shake">
              {error}
            </div>
          )}

          <div className="space-y-6">
            <div className="space-y-3">
              <Label
                htmlFor="name"
                className="text-[10px] font-black uppercase tracking-[0.2em] text-text-tertiary"
              >
                {t("platform_name")}
              </Label>
              <Input
                id="name"
                name="name"
                defaultValue={editingPlatform?.name}
                required
                placeholder="e.g. PlayStation 5"
                className="bg-white/5 border-white/10 h-14 rounded-xl text-white font-bold focus:ring-brand-primary"
              />
            </div>

            <div className="space-y-3">
              <Label
                htmlFor="icon_url"
                className="text-[10px] font-black uppercase tracking-[0.2em] text-text-tertiary"
              >
                {t("platform_icon")}
              </Label>
              <Input
                id="icon_url"
                name="icon_url"
                defaultValue={editingPlatform?.icon_url || ""}
                placeholder="https://example.com/icon.png"
                className="bg-white/5 border-white/10 h-14 rounded-xl text-white font-bold focus:ring-brand-primary"
              />
            </div>
          </div>

          <div className="flex gap-4 pt-4">
            <Button
              type="button"
              variant="ghost"
              onClick={handleCloseModal}
              className="flex-1 h-14 rounded-xl font-black uppercase tracking-widest text-text-tertiary hover:text-white"
            >
              <X className="mr-2 h-4 w-4" /> {common("cancel")}
            </Button>
            <Button
              type="submit"
              disabled={isPending}
              className="flex-1 bg-brand-primary text-white hover:bg-white hover:text-black h-14 rounded-xl font-black uppercase tracking-widest shadow-[0_0_20px_rgba(244,0,9,0.3)] transition-all"
            >
              {isPending ? (
                <Loader2 className="h-5 w-5 animate-spin" />
              ) : (
                <>
                  <Save className="mr-2 h-4 w-4" />{" "}
                  {editingPlatform ? common("save") : t("add_platform")}
                </>
              )}
            </Button>
          </div>
        </form>
      </PremiumModal>
    </div>
  );
}

import { createClient } from "@/lib/supabase/server";
import {
  Users,
  Shield,
  ShieldCheck,
  Mail,
  Calendar,
  Search,
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { getTranslations } from "next-intl/server";

export async function generateMetadata({
  params,
}: {
  params: Promise<{ locale: string }>;
}) {
  const { locale } = await params;
  const t = await getTranslations({ locale, namespace: "Metadata" });
  return { title: t("admin_users") };
}

export default async function AdminUsersPage() {
  const supabase = await createClient();
  const { data: profiles } = await supabase
    .from("profiles")
    .select("*")
    .order("created_at", { ascending: false })
    .limit(20);

  return (
    <div className="space-y-12 animate-in fade-in duration-700">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-6">
        <div>
          <h1 className="font-display text-5xl font-black uppercase tracking-tighter text-white">
            User Directory
          </h1>
          <p className="text-text-secondary mt-2 font-medium">
            Monitor and manage all platform participants and organizers.
          </p>
        </div>
        <div className="relative w-full md:w-96">
          <Search className="absolute left-6 top-1/2 -translate-y-1/2 h-5 w-5 text-text-tertiary" />
          <Input
            className="bg-white/5 border-white/5 pl-14 h-16 rounded-2xl text-white font-bold uppercase tracking-widest text-xs focus:border-brand-primary transition-all shadow-2xl"
            placeholder="Search nickname or email..."
          />
        </div>
      </div>

      {/* USERS LIST */}
      <div className="bg-[#0c0c0e] border border-white/5 rounded-[3rem] overflow-hidden shadow-2xl">
        <div className="p-6 bg-white/2 border-b border-white/5 grid grid-cols-4 text-[10px] font-black uppercase tracking-widest text-text-tertiary px-10">
          <span>Profile</span>
          <span>Role</span>
          <span>Joined Date</span>
          <span className="text-right">Action</span>
        </div>
        <div className="divide-y divide-white/5">
          {profiles?.map((profile) => (
            <div
              key={profile.id}
              className="px-10 py-8 grid grid-cols-4 items-center hover:bg-white/2 transition-all group"
            >
              <div className="flex items-center gap-4">
                <div className="h-12 w-12 rounded-2xl bg-brand-subtle flex items-center justify-center text-brand-primary border border-brand-primary/10 group-hover:scale-110 transition-transform">
                  <Users className="h-6 w-6" />
                </div>
                <div className="truncate">
                  <div className="font-black text-white uppercase tracking-tight truncate">
