                            >
                              <Settings className="h-4 w-4" />
                            </Button>
                            <Button
                              variant="ghost"
                              size="icon"
                              onClick={() => setPlayerToDelete(player.id)}
                              className="h-9 w-9 text-text-tertiary hover:text-error hover:bg-error/5"
