export async function generateMetadata({
  params,
}: {
  params: Promise<{ id: string; locale: string }>;
}) {
  const { id } = await params;
  const supabase = await createClient();
  const { data: tournament } = await supabase
    .from("tournaments")
    .select("name")
    .eq("id", id)
    .single();

  if (!tournament) return { title: "Tournament Not Found" };

  return { title: tournament.name };
}

export default async function PublicTournamentDetailPage({
  params,
}: {
  params: Promise<{ id: string; locale: string }>;
}) {
  const tCommon = await getTranslations("Common");
  const t = await getTranslations("Tournament");
  const { id, locale } = await params;
  const supabase = await createClient();
  const {
    data: { user },
  } = await supabase.auth.getUser();

  const { data: tournament } = await supabase
    .from("tournaments")
    .select(
      "*, projects(name, logo_url), games(name, cover_url), tournament_platforms(platforms(name))",
    )
    .eq("id", id)
    .single();

  if (!tournament) {
    notFound();
  }

  // Fetch stages and matches
  const { data: stages } = await supabase
    .from("stages")
    .select("*")
    .eq("tournament_id", id)
    .order("order_index", { ascending: true });

  const currentStage = stages?.[0];

  const { data: matches } = await supabase
    .from("matches")
    .select(
      "*, p1:participants!participant1_id(name, logo_url), p2:participants!participant2_id(name, logo_url), rounds(number, name)",
    )
    .eq("stage_id", currentStage?.id || "")
    .order("match_number", { ascending: true });

  const { count: participantCount } = await supabase
    .from("participants")
    .select("id", { count: "exact", head: true })
    .eq("tournament_id", id)
    .eq("status", "approved");

  // Check if user is already registered
  let isRegistered = false;
  let isPending = false;
  if (user) {
    const { data: registration } = await supabase
      .from("registrations")
      .select("status")
      .eq("tournament_id", id)
      .eq("user_id", user.id)
      .single();

    if (registration) {
      isRegistered = true;
      isPending = registration.status === "pending";
    }
  }

  const fDate = (dateStr?: string) => {
    if (!dateStr) return "N/A";
