                ))}
            </div>
          </div>
        ))}
      </div>

      {selectedMatch && (
        <MatchDetailModal
          isOpen={!!selectedMatch}
          onClose={() => setSelectedMatch(null)}
          match={selectedMatch}
          tournamentId={tournamentId}
